# critical_path.py — simplified critical path calculation for small programmes

from typing import Dict, List, Optional

class Task:
    def __init__(self, id: str, name: str, duration: float, predecessors: List[str]):
        self.id = id
        self.name = name
        self.duration = duration
        self.predecessors = predecessors
        self.earliest_start = 0.0
        self.earliest_finish = 0.0
        self.latest_start = float('inf')
        self.latest_finish = float('inf')
        self.float = 0.0

def calculate_critical_path(tasks: Dict[str, Task]) -> List[str]:
    # Forward pass: compute earliest start and finish
    changed = True
    while changed:
        changed = False
        for task in tasks.values():
            es = 0.0
            for pred_id in task.predecessors:
                pred = tasks[pred_id]
                es = max(es, pred.earliest_finish)
            ef = es + task.duration
            if es != task.earliest_start or ef != task.earliest_finish:
                task.earliest_start = es
                task.earliest_finish = ef
                changed = True

    # Project end date is max earliest_finish across all tasks
    project_end = max(t.earliest_finish for t in tasks.values())

    # Backward pass: compute latest start and finish
    for task in tasks.values():
        if not any(task.id in t.predecessors for t in tasks.values()):
            task.latest_finish = project_end
            task.latest_start = project_end - task.duration

    changed = True
    while changed:
        changed = False
        for task in tasks.values():
            lf = float('inf')
            for other in tasks.values():
                if task.id in other.predecessors:
                    lf = min(lf, other.latest_start)
            if lf == float('inf'):
                lf = project_end
            ls = lf - task.duration
            if lf != task.latest_finish or ls != task.latest_start:
                task.latest_finish = lf
                task.latest_start = ls
                changed = True

    # Float = latest_start - earliest_start; zero float = critical path
    critical_path = []
    for task in tasks.values():
        task.float = task.latest_start - task.earliest_start
        if abs(task.float) < 0.001:
            critical_path.append(task.id)

    return critical_path

if __name__ == "__main__":
    tasks = {
        "A": Task("A", "Data pipeline build", 3, []),
        "B": Task("B", "Model fine-tuning", 4, ["A"]),
        "C": Task("C", "Evaluation harness", 2, ["A"]),
        "D": Task("D", "Safety review", 3, ["B", "C"]),
        "E": Task("E", "Production deployment", 1, ["D"]),
    }
    cp = calculate_critical_path(tasks)
    print(f"Critical path: {cp}")
    for tid in cp:
        t = tasks[tid]
        print(f"  {t.name}: ES={t.earliest_start:.1f}, EF={t.earliest_finish:.1f}, Float={t.float:.1f}")

# buffer_management.py — critical chain buffer tracking

from dataclasses import dataclass
from typing import List

@dataclass
class ProgrammeBuffer:
    name: str
    original_size_days: float
    consumed_days: float = 0.0

    @property
    def remaining_days(self) -> float:
        return self.original_size_days - self.consumed_days

    @property
    def consumption_fraction(self) -> float:
        if self.original_size_days == 0:
            return 0.0
        return self.consumed_days / self.original_size_days

    @property
    def status(self) -> str:
        f = self.consumption_fraction
        if f < 0.33:
            return "green"
        elif f < 0.67:
            return "amber"
        else:
            return "red"

    def consume(self, days: float, reason: str) -> None:
        self.consumed_days += days
        new_status = self.status
        print(f"Buffer '{self.name}' consumed {days}d for '{reason}'. "
              f"Remaining: {self.remaining_days:.1f}d ({self.consumption_fraction:.0%}). "
              f"Status: {new_status}")
        if new_status == "amber":
            print(f"  WARNING: Buffer '{self.name}' is at amber — review critical path.")
        elif new_status == "red":
            print(f"  ESCALATION: Buffer '{self.name}' is at red — programme manager action required.")

# Example usage
programme_buffer = ProgrammeBuffer("Q2 Programme Buffer", original_size_days=10)
programme_buffer.consume(2, "Model evaluation took 2 extra days due to accuracy gap")
programme_buffer.consume(2, "EHR integration API certification delayed")
programme_buffer.consume(4, "Security audit required additional evidence")
